	//// ----- Metadata -----
	//// One subtype per line so the AST is never ambiguous (no shared MetadataField with default enum status).
	//MetadataField:
	//    MetadataTitleField
	//    | MetadataVersionField
	//    | MetadataStatusField
	//    | MetadataModuleField
	//    | MetadataJavaPackageField
